  1→import { useState, useCallback, useRef, useMemo, useEffect, createElement } from "react";
  2→import { AnimatePresence, motion } from "framer-motion";
  3→import { ArrowUp, ChevronDown, Check, FolderOpen, GitBranch, Search, Upload } from "lucide-react";
  4→import { capabilities } from "@/platform/capabilities";
  5→import { cn } from "@/shared/lib/utils";
  6→import { getAgentLogo } from "@/assets/agents";
  7→import {
  8→  getRuntimeModelLabel,
  9→  getRuntimeModelOption,
 10→  RUNTIME_MODEL_OPTIONS,
 11→  MODEL_PICKER_GROUPS,
 12→  type RuntimeAgentType,
 13→} from "@/features/session/lib/agentRuntime";
 14→import { useImageAttachments } from "@/features/session/hooks/useImageAttachments";
 15→import { PastedImageCard } from "@/features/session/ui/PastedImageCard";
 16→import { BranchSelector } from "@/features/workspace/ui/BranchSelector";
 17→import type { Repository } from "../types";
 18→
 19→// ── Easing ──────────────────────────────────────────────────────────
 20→const EASE_OUT_QUART: [number, number, number, number] = [0.165, 0.84, 0.44, 1];
 21→
 22→// ── Persistence ─────────────────────────────────────────────────────
 23→const LAST_REPO_KEY = "deus:welcome-last-repo";
 24→const LAST_MODEL_KEY = "deus:welcome-last-model";
 25→
 26→function getStoredRepoId(): string | null {
 27→  try {
 28→    return localStorage.getItem(LAST_REPO_KEY);
 29→  } catch {
 30→    return null;
 31→  }
 32→}
 33→
 34→function setStoredRepoId(id: string) {
 35→  try {
 36→    localStorage.setItem(LAST_REPO_KEY, id);
 37→  } catch {
 38→    /* localStorage unavailable */
 39→  }
 40→}
 41→
 42→function getStoredModel(): string {
 43→  try {
 44→    return localStorage.getItem(LAST_MODEL_KEY) ?? "claude:sonnet";
 45→  } catch {
 46→    return "claude:sonnet";
 47→  }
 48→}
 49→
 50→function setStoredModel(model: string) {
 51→  try {
 52→    localStorage.setItem(LAST_MODEL_KEY, model);
 53→  } catch {
 54→    /* localStorage unavailable */
 55→  }
 56→}
 57→
 58→// ── Quick Prompts ───────────────────────────────────────────────────
 59→const QUICK_PROMPTS = [
 60→  "Find and fix bugs",
 61→  "Write missing tests",
 62→  "Explain this codebase",
 63→  "Clean up the code",
 64→  "Update dependencies",
 65→];
 66→
 67→// ── Types ───────────────────────────────────────────────────────────
 68→interface HomeViewProps {
 69→  repos: Repository[];
 70→  onSendMessage: (repoId: string, message: string, model: string, branch?: string) => void;
 71→  onOpenProject?: () => void;
 72→  onCloneRepository?: () => void;
 73→}
 74→
 75→// ── Agent Logo Helper ───────────────────────────────────────────────
 76→// Render agent logo by type. Uses createElement to avoid React Compiler's
 77→// static-components rule (dynamic <Logo /> references are flagged).
 78→function AgentLogo({ type, className }: { type: RuntimeAgentType; className?: string }) {
 79→  const Logo = getAgentLogo(type);
 80→  if (!Logo) {
 81→    return <span className={cn("bg-muted-foreground/80 inline-flex rounded-full", className)} />;
 82→  }
 83→  return createElement(Logo, { className: cn("flex-shrink-0", className) });
 84→}
 85→
 86→// ── Path Utility ────────────────────────────────────────────────────
 87→function abbreviatePath(path: string): string {
 88→  const home = path.match(/^\/Users\/[^/]+/)?.[0];
 89→  if (home) return path.replace(home, "~");
 90→  return path;
 91→}
 92→
 93→/**
 94→ * HomeView — "Gravity Well" input-first workspace launcher.
 95→ *
 96→ * Design direction: The message input is the gravitational center.
 97→ * Repo picker and model selector live in a context bar at the top
 98→ * of the input card. Quick prompts orbit below. The question headline
 99→ * draws the eye downward into the input.
100→ *
101→ * Flow: user types message + picks repo/model -> onSendMessage()
102→ * -> parent creates workspace + session, transitions to two-panel layout.
103→ */
104→export function HomeView({
105→  repos = [],
106→  onSendMessage,
107→  onOpenProject,
108→  onCloneRepository,
