                      branch.name
                    ) : (
                      <>
                        <span className="text-text-disabled">origin/</span>
                        {branch.name}
                      </>
                    )}
                  </span>
                  {isLocalOnly && (
                    <span className="text-text-disabled text-2xs flex-shrink-0">local</span>
                  )}
                </button>
              );
            })
          )}
        </div>
      </PopoverContent>
    </Popover>
  );
}

